fn backend_policy_from_execution_plan<'a>(
    execution_plan: &'a serde_json::Value,
    backend_id: &str,
) -> Option<&'a serde_json::Value> {
    execution_plan["backend_admissibility_matrix"]
        .as_array()
        .into_iter()
        .flatten()
        .find(|entry| entry["backend_id"].as_str() == Some(backend_id))
}

fn backend_class_from_execution_plan(
    execution_plan: &serde_json::Value,
    backend_id: &str,
) -> Option<String> {
    backend_policy_from_execution_plan(execution_plan, backend_id)
        .and_then(|entry| entry["backend_class"].as_str())
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_string)
}

fn route_execution_posture_from_classes(classes: &[String]) -> &'static str {
    let has_internal = classes.iter().any(|value| value == "internal");
    let has_external = classes.iter().any(|value| value == "external_cli");
    match (has_internal, has_external) {
        (true, true) => "hybrid",
        (true, false) => "internal_only",
        (false, true) => "external_only",
        _ => "unknown",
    }
}

pub(crate) fn dispatch_execution_route_summary(
    role_selection: &RuntimeConsumptionLaneSelection,
    dispatch_target: &str,
    selected_backend: Option<&str>,
) -> serde_json::Value {
    let route =
        execution_plan_route_for_dispatch_target(&role_selection.execution_plan, dispatch_target);
    let route_primary_backend = route.and_then(|entry| {
        selected_backend_from_execution_plan_route(&role_selection.execution_plan, entry)
    });
    let route_fallback_backend = route.and_then(fallback_executor_backend_from_route);
    let route_fanout_backends = route
        .map(fanout_executor_backends_from_route)
        .unwrap_or_default();
    let effective_selected_backend = selected_backend
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_string)
        .or_else(|| route_primary_backend.clone());
    let selected_backend_source = match effective_selected_backend.as_deref() {
        Some(_backend_id) if selected_backend.is_some() => "dispatch_receipt",
        Some(backend_id) if route_primary_backend.as_deref() == Some(backend_id) => "route_primary",
        Some(backend_id) if route_fallback_backend.as_deref() == Some(backend_id) => {
            "route_fallback"

            xdg_data_home.display().to_string(),
        ),
        (
            "XDG_STATE_HOME".to_string(),
            xdg_state_home.display().to_string(),
        ),
        (
            "XDG_CACHE_HOME".to_string(),
            xdg_cache_home.display().to_string(),
        ),
        ("TMPDIR".to_string(), tmpdir.display().to_string()),
    ])
}

fn configured_internal_codex_activation_parts(
    project_root: &Path,
    dispatch_packet_path: &str,
    carrier: &serde_json::Value,
) -> Result<(String, Vec<String>), String> {
    let model = carrier["model"]
        .as_str()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .ok_or_else(|| "Configured Codex carrier is missing model".to_string())?;
    let sandbox_mode = carrier["sandbox_mode"]
        .as_str()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .ok_or_else(|| "Configured Codex carrier is missing sandbox_mode".to_string())?;
    let reasoning_effort = carrier["model_reasoning_effort"]
        .as_str()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .unwrap_or("medium");
    let prompt = dispatch_packet_prompt(dispatch_packet_path);

    Ok((
        "codex".to_string(),
        vec![
            "exec".to_string(),
            "--json".to_string(),
            "-C".to_string(),
            project_root.display().to_string(),
            "-s".to_string(),
            sandbox_mode.to_string(),
            "-m".to_string(),
            model.to_string(),
            "-c".to_string(),
            format!("model_reasoning_effort=\"{reasoning_effort}\""),
            prompt,
        ],
    ))
}

pub(crate) fn agent_lane_dispatch_result(
    mut activation_view: serde_json::Value,
    dispatch_packet_path: &str,
    preferred_backend: Option<&str>,
    role_selection: &RuntimeConsumptionLaneSelection,
    receipt: &crate::state_store::RunGraphDispatchReceipt,
    host_runtime: serde_json::Value,
) -> serde_json::Value {
    let effective_selected_backend =
        crate::runtime_dispatch_state::canonical_selected_backend_for_receipt(
            role_selection,
            receipt,
        )
        .or_else(|| receipt.selected_backend.clone());
    let project_root = std::env::current_dir().unwrap_or_else(|_| PathBuf::from("."));
    let lane_dispatch = crate::runtime_dispatch_state::runtime_agent_lane_dispatch_for_root(
        &project_root,
        dispatch_packet_path,
        preferred_backend,
    );
    let effective_execution_posture =
        crate::runtime_dispatch_state::effective_execution_posture_summary(
            &role_selection.execution_plan,
            &receipt.dispatch_target,
            effective_selected_backend.as_deref(),
            receipt.activation_agent_type.as_deref(),
            Some(&host_runtime),
            false,
        );
    let execution_truth = summarize_execution_truth_for_route(
        &role_selection.execution_plan,
        crate::runtime_dispatch_state::execution_plan_route_for_dispatch_target(
            &role_selection.execution_plan,
            &receipt.dispatch_target,
        ),
        host_runtime["selected_cli_execution_class"].as_str(),
        effective_selected_backend.as_deref(),
        Some("activation_view"),
        Some("missing"),
    );
    let body = activation_view
        .as_object_mut()
        .expect("agent-init activation view should serialize to an object");
    body.insert(
        "surface".to_string(),
        serde_json::json!(lane_dispatch.surface),
    );
    body.insert("status".to_string(), serde_json::json!("blocked"));
    body.insert("execution_state".to_string(), serde_json::json!("blocked"));
    body.insert(
        "activation_command".to_string(),
        serde_json::json!(lane_dispatch.activation_command),
    );
    body.insert(
        "dispatch_packet_path".to_string(),
        serde_json::json!(dispatch_packet_path),
    );
    body.insert("host_runtime".to_string(), host_runtime);
    body.insert(
        "effective_execution_posture".to_string(),
        effective_execution_posture,
    );
    body.insert("execution_truth".to_string(), execution_truth);
    body.insert(
        "blocker_code".to_string(),
        serde_json::json!("internal_activation_view_only"),
    );
    body.insert(
        "blocker_reason".to_string(),
        serde_json::json!(
            "selected host/backend returned only an activation view without execution evidence"
        ),
    );
    body.insert(
        "backend_dispatch".to_string(),
        lane_dispatch.backend_dispatch,
    );
    body.insert(
        "role_selection".to_string(),
        serde_json::to_value(role_selection).expect("lane selection should serialize"),
    );
    activation_view
}

fn refresh_execution_truth(
    body: &mut serde_json::Map<String, serde_json::Value>,
    role_selection: &RuntimeConsumptionLaneSelection,
    receipt: &crate::state_store::RunGraphDispatchReceipt,
    effective_selected_backend: Option<&str>,
    execution_evidence_status: &str,
) {
    let host_runtime = body
        .get("host_runtime")
        .cloned()
        .unwrap_or(serde_json::Value::Null);
    let activation_kind = body
        .get("activation_semantics")
        .and_then(|value| value.get("activation_kind"))
        .and_then(serde_json::Value::as_str)
        .unwrap_or("unknown");
    body.insert(
        "execution_truth".to_string(),
        summarize_execution_truth_for_route(
            &role_selection.execution_plan,
            crate::runtime_dispatch_state::execution_plan_route_for_dispatch_target(
                &role_selection.execution_plan,
                &receipt.dispatch_target,
            ),
            host_runtime["selected_cli_execution_class"].as_str(),
            effective_selected_backend,
            Some(activation_kind),
            Some(execution_evidence_status),
        ),
    );
}

fn mark_dispatch_result_execution_evidence(
    body: &mut serde_json::Map<String, serde_json::Value>,
    evidence_kind: &str,
    backend_id: &str,
) {
    let activation_semantics = body
        .entry("activation_semantics".to_string())
        .or_insert_with(|| serde_json::json!({}));
    let activation_semantics = activation_semantics
        .as_object_mut()
        .expect("activation_semantics should serialize to an object");
    activation_semantics.insert(
        "activation_kind".to_string(),
        serde_json::json!("execution_evidence"),
    );
    activation_semantics.insert("view_only".to_string(), serde_json::json!(false));
    activation_semantics.insert("executes_packet".to_string(), serde_json::json!(true));
    activation_semantics.insert(
        "records_completion_receipt".to_string(),
        serde_json::json!(true),
    );
    activation_semantics.insert(
        "transfers_root_session_write_authority".to_string(),
        serde_json::json!(false),
    );
    activation_semantics.insert(
        "root_session_write_guard_remains_authoritative".to_string(),
        serde_json::json!(true),
    );
    activation_semantics.insert(
        "next_lawful_action".to_string(),
        serde_json::json!(
            "treat this result as receipt-backed delegated-lane execution evidence and continue through runtime downstream progression"
        ),
    );
    body.insert(
        "execution_evidence".to_string(),
        serde_json::json!({
            "status": "recorded",
            "evidence_kind": evidence_kind,
            "backend_id": backend_id,
            "receipt_backed": true,
            "records_dispatch_result": true,
        }),
    );
    if let Some(posture) = body
        .get_mut("effective_execution_posture")
        .and_then(serde_json::Value::as_object_mut)
    {
        posture.insert(
            "activation_evidence_state".to_string(),
            serde_json::json!("execution_evidence"),
        );
        posture.insert(
            "receipt_backed_execution_evidence".to_string(),
            serde_json::json!(true),
        );
        posture.insert(
            "selected_backend".to_string(),
            serde_json::json!(backend_id),
        );
    }
    if let Some(posture) = body
        .get_mut("execution_truth")
        .and_then(serde_json::Value::as_object_mut)
    {
        posture.insert(
            "effective_selected_backend".to_string(),
            serde_json::json!(backend_id),
        );
        if let Some(activation_evidence) = posture
            .get_mut("activation_evidence")
            .and_then(serde_json::Value::as_object_mut)
        {
            activation_evidence.insert(
                "activation_kind".to_string(),
                serde_json::json!("execution_evidence"),
            );
            activation_evidence.insert(
                "execution_evidence_status".to_string(),
                serde_json::json!("recorded"),
            );
            activation_evidence.insert("receipt_backed".to_string(), serde_json::json!(true));
        }
    }
}

pub(crate) async fn execute_internal_agent_lane_dispatch(
    state_root: &Path,
    project_root: &Path,
    dispatch_packet_path: &str,
    preferred_backend: Option<&str>,
    role_selection: &RuntimeConsumptionLaneSelection,
    receipt: &crate::state_store::RunGraphDispatchReceipt,
    host_runtime: serde_json::Value,
) -> Result<Option<serde_json::Value>, String> {
    let overlay = crate::runtime_dispatch_state::load_project_overlay_yaml_for_root(project_root)?;
    let (selected_cli_system, selected_cli_entry) =
        crate::runtime_dispatch_state::selected_host_cli_system_for_runtime_dispatch(&overlay);
    let execution_class = selected_cli_entry
        .as_ref()
        .and_then(|entry| yaml_lookup(entry, &["execution_class"]))
        .and_then(serde_yaml::Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .unwrap_or_else(|| {
            host_runtime["selected_cli_execution_class"]
                .as_str()
                .unwrap_or("unknown")
        });
    if selected_cli_system != "codex" || execution_class != "internal" {
        return Ok(None);
    }

    let Some(carrier) = selected_internal_codex_carrier(
        selected_cli_entry.as_ref(),
        preferred_backend,
        receipt,
        role_selection,
    ) else {
        return Ok(None);
    };

    let carrier_id = carrier["role_id"].as_str().unwrap_or("codex");
    let (command, args) =
        configured_internal_codex_activation_parts(project_root, dispatch_packet_path, &carrier)?;
    let wall_timeout_seconds = Some(configured_internal_codex_dispatch_wall_timeout_seconds(
        selected_cli_entry.as_ref(),
    ));
    let wrapped_command =
        wrap_command_with_optional_timeout(command.clone(), args.clone(), wall_timeout_seconds);
    let activation_command = crate::runtime_dispatch_state::render_command_display(
        &wrapped_command.command,
        &wrapped_command.args,
    );
    let runtime_env = configured_internal_codex_runtime_env(project_root, carrier_id)?;

    let mut process = std::process::Command::new(&wrapped_command.command);
    process
        .args(&wrapped_command.args)
        .current_dir(project_root);
    for (key, value) in runtime_env {
        process.env(key, value);
    }
    process.env("VIDA_DISPATCH_PACKET_PATH", dispatch_packet_path);
    process.env("VIDA_DISPATCH_TARGET", &receipt.dispatch_target);
    process.env("VIDA_SELECTED_CLI_SYSTEM", &selected_cli_system);
    process.env("VIDA_SELECTED_BACKEND", carrier_id);
    if let Some(runtime_role) = receipt.activation_runtime_role.as_deref() {
        process.env("VIDA_RUNTIME_ROLE", runtime_role);
    }

    let output = process.output().map_err(|error| {
        format!(
            "Failed to execute internal Codex carrier `{carrier_id}` via `{}`: {error}",
            wrapped_command.command
        )
    })?;
    let activation_view = match StateStore::open_existing(state_root.to_path_buf()).await {
        Ok(store) => {
            let rendered = crate::init_surfaces::render_agent_init_packet_activation_with_store(
                &store,
                project_root,
                dispatch_packet_path,
                false,
            )
            .await
            .unwrap_or_else(|_| {
                serde_json::json!({
                    "selection": {
                        "mode": "dispatch_packet",
                        "selected_role": receipt
                            .activation_runtime_role
                            .as_deref()
                            .unwrap_or(&role_selection.selected_role),
                    },
                    "activation_semantics": {
                        "activation_kind": "activation_view",
                        "view_only": true,
                    },
                })
            });
            drop(store);
            rendered
        }
        Err(_) => serde_json::json!({
            "selection": {
                "mode": "dispatch_packet",
                "selected_role": receipt
                    .activation_runtime_role
                    .as_deref()

                    .as_deref()
                    .unwrap_or(&role_selection.selected_role),
            },
            "activation_semantics": {
                "activation_kind": "activation_view",
                "view_only": true,
            },
        }),
    };
    let mut result = agent_lane_dispatch_result(
        activation_view,
        dispatch_packet_path,
        preferred_backend,
        role_selection,
        receipt,
        host_runtime,
    );
    let body = result
        .as_object_mut()
        .expect("internal agent lane dispatch result should serialize to an object");
    body.insert(
        "surface".to_string(),
        serde_json::json!("internal_cli:codex"),
    );
    body.insert(
        "activation_command".to_string(),
        serde_json::json!(activation_command),
    );
    if let Some(dispatch) = body
        .get_mut("backend_dispatch")
        .and_then(serde_json::Value::as_object_mut)
    {
        dispatch.insert("backend_class".to_string(), serde_json::json!("internal"));
        dispatch.insert("backend_id".to_string(), serde_json::json!(carrier_id));
        dispatch.insert(
            "carrier_id".to_string(),
            serde_json::json!(carrier["role_id"].clone()),
        );
        dispatch.insert(
            "model".to_string(),
            serde_json::json!(carrier["model"].clone()),
        );
        dispatch.insert(
            "model_reasoning_effort".to_string(),
            serde_json::json!(carrier["model_reasoning_effort"].clone()),
        );
        dispatch.insert(
            "sandbox_mode".to_string(),
            serde_json::json!(carrier["sandbox_mode"].clone()),
        );
    }

    let stdout = String::from_utf8_lossy(&output.stdout).trim().to_string();
    let stderr = String::from_utf8_lossy(&output.stderr).trim().to_string();
    let parsed_output = parse_internal_codex_exec_output(&stdout);
    let exit_code = output.status.code();
    let timed_out = wrapped_command.timed_out(exit_code);
    let activation_only = timed_out
        || (output.status.success()
            && parsed_output.result_text.is_none()
            && parsed_output.error_messages.is_empty());
    let success = output.status.success() && parsed_output.result_text.is_some();

    body.insert(
        "status".to_string(),
        serde_json::json!(if success { "pass" } else { "blocked" }),
    );
    body.insert(
        "execution_state".to_string(),
        serde_json::json!(if success { "executed" } else { "blocked" }),
    );
    body.insert("provider_output".to_string(), serde_json::json!(stdout));
    body.insert("provider_error".to_string(), serde_json::json!(stderr));
    body.insert("exit_code".to_string(), serde_json::json!(exit_code));
    if let Some(timeout_wrapper) = &wrapped_command.timeout_wrapper {
        body.insert(
            "timeout_wrapper".to_string(),
            serde_json::json!({
                "command": wrapped_command.command,
                "timeout_seconds": timeout_wrapper.timeout_seconds,
                "kill_after_grace_seconds": timeout_wrapper.kill_after_grace_seconds,
                "timed_out": timed_out,
                "timeout_exit_code": exit_code,
            }),
        );
    }
    body.insert(
        "provider_output_json".to_string(),
        parsed_output.raw_json.clone(),
    );
    body.insert(
        "provider_result".to_string(),
        parsed_output
            .result_text
            .clone()
            .map(serde_json::Value::String)
            .unwrap_or(serde_json::Value::Null),
    );
    body.insert(
        "provider_error_items".to_string(),
        serde_json::to_value(parsed_output.error_messages.clone())
            .expect("internal codex error items should serialize"),
    );
    if success {
        body.insert("blocker_code".to_string(), serde_json::Value::Null);
        body.insert("blocker_reason".to_string(), serde_json::Value::Null);
        mark_dispatch_result_execution_evidence(body, "internal_carrier_completion", carrier_id);
        refresh_execution_truth(body, role_selection, receipt, Some(carrier_id), "recorded");
    } else if activation_only {
        if timed_out {
            let timeout_seconds = wrapped_command
                .timeout_wrapper
                .as_ref()
                .map(|wrapper| wrapper.timeout_seconds)
                .unwrap_or_default();
            let kill_after_grace_seconds = wrapped_command
                .timeout_wrapper
                .as_ref()
                .map(|wrapper| wrapper.kill_after_grace_seconds)
                .unwrap_or_default();
            body.insert(
                "provider_error".to_string(),
                serde_json::json!(format!(
                    "internal Codex carrier timed out after {timeout_seconds}s and kill-after grace {kill_after_grace_seconds}s without receipt-backed completion"
                )),
            );
        }
        let blocker_reason = if timed_out {
            "internal Codex carrier exceeded the bounded runtime window before returning execution evidence".to_string()
        } else {
            "internal Codex carrier completed without returning an agent_message result".to_string()
        };
        body.insert(
            "blocker_code".to_string(),
            serde_json::json!("internal_activation_view_only"),
        );
        body.insert(
            "blocker_reason".to_string(),
            serde_json::json!(blocker_reason),
        );
        refresh_execution_truth(body, role_selection, receipt, Some(carrier_id), "missing");
    } else {
        let blocker_reason = if !stderr.is_empty() {
            stderr
        } else if !parsed_output.error_messages.is_empty() {
            parsed_output.error_messages.join("\n")
        } else if output.status.success() {
            "internal Codex carrier completed without returning an agent_message result".to_string()
        } else {
            "internal Codex carrier exited without returning receipt-backed completion".to_string()
        };
        body.insert(
            "blocker_code".to_string(),
            serde_json::json!("configured_backend_dispatch_failed"),
        );
        body.insert(
            "blocker_reason".to_string(),
            serde_json::json!(blocker_reason),
        );
        refresh_execution_truth(body, role_selection, receipt, Some(carrier_id), "missing");
    }

    Ok(Some(result))
}

pub(crate) async fn execute_external_agent_lane_dispatch(
    state_root: &Path,
    project_root: &Path,
    dispatch_packet_path: &str,
    preferred_backend: Option<&str>,
    role_selection: &RuntimeConsumptionLaneSelection,
    receipt: &crate::state_store::RunGraphDispatchReceipt,
    host_runtime: serde_json::Value,
) -> Result<serde_json::Value, String> {
    let overlay = crate::runtime_dispatch_state::load_project_overlay_yaml_for_root(project_root)?;
    let (selected_cli_system, _) =
        crate::runtime_dispatch_state::selected_host_cli_system_for_runtime_dispatch(&overlay);
    let backend_class = crate::runtime_dispatch_state::configured_dispatch_backend_class(
        &overlay,
        &selected_cli_system,
    );
    let (backend_id, backend_entry) =
        crate::runtime_dispatch_state::selected_external_backend_for_system(
            &overlay,
            &selected_cli_system,
            preferred_backend,
        )
            .ok_or_else(|| {
                format!(
                    "Configured host CLI system `{selected_cli_system}` has no enabled external backend dispatch adapter"
                )
            })?;
    let (command, args) = crate::runtime_dispatch_state::configured_external_activation_parts(
        &backend_entry,
        project_root,
        dispatch_packet_path,
    )?;
    let wall_timeout_seconds = configured_external_dispatch_wall_timeout_seconds(&backend_entry);
    let wrapped_command =
        wrap_command_with_optional_timeout(command.clone(), args.clone(), wall_timeout_seconds);
    let activation_command = crate::runtime_dispatch_state::render_command_display(
        &wrapped_command.command,
        &wrapped_command.args,
    );

    let mut process = std::process::Command::new(&wrapped_command.command);
    process
        .args(&wrapped_command.args)
        .current_dir(project_root);
    if let Some(serde_yaml::Value::Mapping(env_map)) =
        yaml_lookup(&backend_entry, &["dispatch", "env"])
    {
        for (key, value) in env_map {
            if let (Some(key), Some(value)) = (key.as_str(), value.as_str()) {
                process.env(key, value);
            }
        }
    }
    process.env("VIDA_DISPATCH_PACKET_PATH", dispatch_packet_path);
    process.env("VIDA_DISPATCH_TARGET", &receipt.dispatch_target);
    process.env("VIDA_SELECTED_CLI_SYSTEM", &selected_cli_system);
    if let Some(runtime_role) = receipt.activation_runtime_role.as_deref() {
        process.env("VIDA_RUNTIME_ROLE", runtime_role);
    }
    let effective_selected_backend = crate::runtime_dispatch_state::canonical_selected_backend_for_receipt(
        role_selection,
        receipt,
    )
    .or_else(|| receipt.selected_backend.clone());
    if let Some(selected_backend) = effective_selected_backend.as_deref() {
        process.env("VIDA_SELECTED_BACKEND", selected_backend);
    }

    let output = process.output().map_err(|error| {
        format!(
            "Failed to execute configured external backend `{backend_id}` via `{}`: {error}",
            wrapped_command.command
        )
    })?;
    let activation_view = match StateStore::open_existing(state_root.to_path_buf()).await {
        Ok(store) => {
            let rendered = crate::init_surfaces::render_agent_init_packet_activation_with_store(
                &store,
                project_root,
                dispatch_packet_path,
                false,
            )
            .await
            .unwrap_or_else(|_| {
                serde_json::json!({
                    "selection": {
                        "mode": "dispatch_packet",
                        "selected_role": receipt
                            .activation_runtime_role
                            .as_deref()
                            .unwrap_or(&role_selection.selected_role),
                    },
                    "activation_semantics": {
                        "activation_kind": "activation_view",
                        "view_only": true,
                    },
                })
            });
            drop(store);
            rendered
        }
        Err(_) => serde_json::json!({
            "selection": {
                "mode": "dispatch_packet",
                "selected_role": receipt
                    .activation_runtime_role
                    .as_deref()
                    .unwrap_or(&role_selection.selected_role),
            },
            "activation_semantics": {
                "activation_kind": "activation_view",
                "view_only": true,
            },
        }),
    };
    let mut result = agent_lane_dispatch_result(
        activation_view,
        dispatch_packet_path,
        preferred_backend,
        role_selection,
        receipt,
        host_runtime,
    );
    let body = result
        .as_object_mut()
        .expect("agent lane dispatch result should serialize to an object");
    body.insert(
        "surface".to_string(),
        serde_json::json!(format!("{backend_class}:{backend_id}")),
    );
    body.insert(
        "activation_command".to_string(),
        serde_json::json!(activation_command),
    );
    if let Some(dispatch) = body
        .get_mut("backend_dispatch")
        .and_then(serde_json::Value::as_object_mut)
    {
        dispatch.insert(
            "backend_class".to_string(),
            serde_json::json!(backend_class),
        );
    }
    let stdout = String::from_utf8_lossy(&output.stdout).trim().to_string();
    let stderr = String::from_utf8_lossy(&output.stderr).trim().to_string();
    let parsed_output = parse_external_provider_output(&stdout);
    let provider_reported_error = parsed_output
        .as_ref()
        .and_then(|parsed| parsed.is_error)
        .unwrap_or(false);
    let success = output.status.success() && !provider_reported_error;
    let exit_code = output.status.code();
    let timed_out = wrapped_command.timed_out(exit_code);
    body.insert(
        "status".to_string(),
        serde_json::json!(if success { "pass" } else { "blocked" }),
    );
    body.insert(
        "execution_state".to_string(),
        serde_json::json!(if success { "executed" } else { "blocked" }),
    );
    body.insert("provider_output".to_string(), serde_json::json!(stdout));
    body.insert("provider_error".to_string(), serde_json::json!(stderr));
    body.insert("exit_code".to_string(), serde_json::json!(exit_code));
    if let Some(timeout_wrapper) = &wrapped_command.timeout_wrapper {
        body.insert(
            "timeout_wrapper".to_string(),
            serde_json::json!({
                "command": wrapped_command.command,
                "timeout_seconds": timeout_wrapper.timeout_seconds,
                "kill_after_grace_seconds": timeout_wrapper.kill_after_grace_seconds,
                "timed_out": timed_out,
                "timeout_exit_code": exit_code,
            }),
        );
    }
    if let Some(parsed_output) = parsed_output {
        body.insert("provider_output_json".to_string(), parsed_output.raw_json);
        body.insert(
            "provider_result".to_string(),
            parsed_output
                .result_text
                .map(serde_json::Value::String)
                .unwrap_or(serde_json::Value::Null),
        );
        body.insert(
            "provider_usage".to_string(),
            parsed_output.usage.unwrap_or(serde_json::Value::Null),
        );
        body.insert(
            "provider_is_error".to_string(),
            parsed_output
                .is_error
                .map(serde_json::Value::Bool)
                .unwrap_or(serde_json::Value::Null),
        );

        }
        if object.get("selected_backend").is_none() {
            if let Some(value) = object
                .get("effective_selected_backend")
                .cloned()
                .or_else(|| object.get("selected_backend").cloned())
            {
                object.insert("selected_backend".to_string(), value);
            }
        }
        if object.get("fanout_backends").is_none() {
            if let Some(value) = object
                .get("fanout_backends")
                .cloned()
                .or_else(|| object.get("fanout_executor_backends").cloned())
            {
                object.insert("fanout_backends".to_string(), value);
            }
        }
        if object.get("fallback_backend").is_none() {
            if let Some(value) = object
                .get("fallback_backend")
                .cloned()
                .or_else(|| object.get("fallback_executor_backend").cloned())
                .or_else(|| object.get("route_fallback_backend").cloned())
            {
                object.insert("fallback_backend".to_string(), value);
            }
        }
    }
    let activation_evidence = packet
        .get("activation_vs_execution_evidence")
        .cloned()
        .or_else(|| packet.get("activation_evidence").cloned())
        .or_else(|| {
            dispatch_receipt.dispatch_result_path.as_deref().and_then(|path| {
                let resolved = resolve_project_artifact_path(project_root, Some(path))?;
                let value = crate::read_json_file_if_present(&resolved)?;
                Some(serde_json::json!({
                    "activation_kind": value["activation_semantics"]["activation_kind"],
                    "evidence_state": if value["execution_evidence"]["status"].as_str() == Some("recorded") {
                        "execution_evidence_recorded"
                    } else {
                        "activation_view_only"
                    },
                    "activation_semantics": value["activation_semantics"].clone(),
                    "execution_evidence": value["execution_evidence"].clone(),
                }))
            })
        });
    Some(serde_json::json!({
        "mixed_posture": mixed_posture.unwrap_or(serde_json::Value::Null),
        "activation_vs_execution_evidence": activation_evidence.unwrap_or(serde_json::Value::Null),
    }))
}

pub(crate) fn fallback_backend_for_blocked_primary_dispatch_receipt(
    project_root: &std::path::Path,
    role_selection: &RuntimeConsumptionLaneSelection,
    dispatch_receipt: &crate::state_store::RunGraphDispatchReceipt,
) -> Option<String> {
    if dispatch_receipt.dispatch_kind != "agent_lane"
        || !dispatch_receipt
            .dispatch_packet_path
            .as_deref()
            .is_some_and(|path| !path.trim().is_empty())
    {
        return None;
    }
    let route = execution_plan_route_for_dispatch_target(
        &role_selection.execution_plan,
        &dispatch_receipt.dispatch_target,
    )?;
    let primary_backend =
        selected_backend_from_execution_plan_route(&role_selection.execution_plan, route)?;
    let fallback_backend = fallback_executor_backend_from_route(route)?;
    if primary_backend == fallback_backend {
        return None;
    }
    let selected_backend = canonical_selected_backend_for_receipt(role_selection, dispatch_receipt)
        .or_else(|| dispatch_receipt.selected_backend.clone())?;
    if selected_backend != primary_backend {
        return None;
    }
    let overlay = load_project_overlay_yaml_for_root(project_root).ok()?;
    let (selected_cli_system, selected_cli_entry) =
        selected_host_cli_system_for_runtime_dispatch(&overlay);
    let preflight = crate::status_surface_external_cli::external_cli_preflight_summary(
        &overlay,
        &selected_cli_system,
        selected_cli_entry.as_ref(),
    );
    let carrier_blocked = preflight["carrier_readiness"]["carriers"]
        .as_array()
        .into_iter()
        .flatten()
        .any(|carrier| {
            carrier["backend_id"].as_str() == Some(primary_backend.as_str())
                && carrier["blocked"].as_bool() == Some(true)
        });
    carrier_blocked.then_some(fallback_backend)
}

pub(crate) fn build_downstream_dispatch_receipt(
    role_selection: &RuntimeConsumptionLaneSelection,
    receipt: &crate::state_store::RunGraphDispatchReceipt,
) -> Option<crate::state_store::RunGraphDispatchReceipt> {
    let dispatch_target = receipt.downstream_dispatch_target.clone()?;
    let recorded_at = time::OffsetDateTime::now_utc()
        .format(&Rfc3339)
        .expect("rfc3339 timestamp should render");
    let (dispatch_kind, dispatch_surface, activation_agent_type, activation_runtime_role) =
        downstream_activation_fields(role_selection, &dispatch_target);
    let selected_backend = downstream_selected_backend(
        role_selection,
        &dispatch_target,
        activation_agent_type.as_deref(),
        receipt.selected_backend.as_deref(),
    )
    .filter(|value| !value.is_empty());
    let dispatch_status = if receipt.downstream_dispatch_ready {
        "routed".to_string()
    } else {
        "blocked".to_string()
    };
    Some(crate::state_store::RunGraphDispatchReceipt {
        run_id: receipt.run_id.clone(),
        dispatch_target: dispatch_target.clone(),
        dispatch_status: dispatch_status.clone(),
        supersedes_receipt_id: receipt.supersedes_receipt_id.clone(),
        exception_path_receipt_id: receipt.exception_path_receipt_id.clone(),
        lane_status: derive_lane_status(
            &dispatch_status,
            receipt.supersedes_receipt_id.as_deref(),
            receipt.exception_path_receipt_id.as_deref(),
        )
        .as_str()
        .to_string(),
        dispatch_kind,
        dispatch_surface,
        dispatch_command: receipt.downstream_dispatch_command.clone(),
        dispatch_packet_path: receipt.downstream_dispatch_packet_path.clone(),
        dispatch_result_path: None,
        blocker_code: if dispatch_status == "blocked" && receipt.dispatch_status != "executed" {
            blocker_code_value(BlockerCode::MissingLaneReceipt)
        } else if dispatch_status == "blocked" && receipt.downstream_dispatch_packet_path.is_none()
        {
            blocker_code_value(BlockerCode::MissingPacket)
        } else {
            None
        },
        downstream_dispatch_target: None,
        downstream_dispatch_command: None,
        downstream_dispatch_note: None,
        downstream_dispatch_ready: false,
        downstream_dispatch_blockers: Vec::new(),
        downstream_dispatch_packet_path: None,
        downstream_dispatch_status: None,
        downstream_dispatch_result_path: None,
        downstream_dispatch_trace_path: None,
        downstream_dispatch_executed_count: 0,
        downstream_dispatch_active_target: None,
        downstream_dispatch_last_target: None,
        activation_agent_type,
        activation_runtime_role,
        selected_backend,
        recorded_at,
    })
}

